const { app } = require('@azure/functions');
const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

app.http('sendNotification', {
    methods: ['POST'],
    authLevel: 'function',
    handler: async (request, context) => {
        try {
            const sendgridApiKey = process.env.SENDGRID_API_KEY;
            const twilioAccountSid = process.env.TWILIO_ACCOUNT_SID;
            const twilioAuthToken = process.env.TWILIO_AUTH_TOKEN;
            const twilioPhoneNumber = process.env.TWILIO_PHONE_NUMBER;

            if (!sendgridApiKey || !twilioAccountSid || !twilioAuthToken) {
                return {
                    status: 500,
                    body: JSON.stringify({ 
                        error: 'Missing required environment variables. Please configure SENDGRID_API_KEY, TWILIO_ACCOUNT_SID, and TWILIO_AUTH_TOKEN in Application Settings.' 
                    })
                };
            }

            const body = await request.json();
            const { type, to, subject, message, from } = body;

            if (!type || !to || !message) {
                return {
                    status: 400,
                    body: JSON.stringify({ error: 'Missing required fields: type, to, message' })
                };
            }

            let result = {};

            if (type === 'email') {
                if (!from || !subject) {
                    return {
                        status: 400,
                        body: JSON.stringify({ error: 'Email requires from and subject fields' })
                    };
                }

                sgMail.setApiKey(sendgridApiKey);
                
                const msg = {
                    to: to,
                    from: from,
                    subject: subject,
                    text: message,
                    html: `<p>${message}</p>`
                };

                await sgMail.send(msg);
                result = { success: true, type: 'email', to: to };

            } else if (type === 'sms') {
                const client = twilio(twilioAccountSid, twilioAuthToken);

                const smsResult = await client.messages.create({
                    body: message,
                    from: twilioPhoneNumber,
                    to: to
                });

                result = { success: true, type: 'sms', to: to, sid: smsResult.sid };

            } else {
                return {
                    status: 400,
                    body: JSON.stringify({ error: 'Invalid type. Must be email or sms' })
                };
            }

            return {
                status: 200,
                body: JSON.stringify(result)
            };

        } catch (error) {
            context.error('Error sending notification:', error);
            return {
                status: 500,
                body: JSON.stringify({ 
                    error: 'Failed to send notification',
                    message: error.message 
                })
            };
        }
    }
});